/* ══════════════════════════════════════
       BLOCK: theme-tags
       Scoped under .block-theme-tags
       ══════════════════════════════════════ */

    .block-theme-tags {
      box-sizing: border-box;
      max-width: 360px;
      width: 100%;
      background: hsl(var(--bg-surface, 0 0% 100%));
      border: 1px solid hsl(var(--border-default, 30 19% 90%));
      border-radius: var(--rounded-2xl, 16px);
      padding: 30px;
      overflow: clip;
    }

    .block-theme-tags__header {
      display: flex;
      align-items: center;
      padding-bottom: var(--spacing-lg, 20px);
      border-bottom: 1px dashed hsl(var(--border-default, 30 19% 90%));
    }

    .block-theme-tags__title {
      margin: 0;
      font-family: inherit;
      font-size: var(--text-base-font-size, 18px);
      line-height: var(--text-base-line-height, 20px);
      letter-spacing: var(--text-base-letter-spacing, 0px);
      font-weight: var(--font-weight-semibold, 600);
      color: hsl(var(--text-primary, 0 0% 9%));
      white-space: nowrap;
    }

    .block-theme-tags__list {
      display: flex;
      flex-wrap: wrap;
      gap: 5px;
      padding-top: var(--spacing-lg, 20px);
    }

    .block-theme-tags__badge {
      display: inline-flex;
      align-items: center;
      justify-content: center;
      padding: var(--spacing-2xs, 4px) var(--spacing-xs, 8px);
      border-radius: var(--rounded-lg, 8px);
      border: 1px solid hsl(var(--button-cta-bg, 206 100% 92%));
      background: hsl(var(--white-alpha-10, 0 0% 100% / 0.1));
      font-family: inherit;
      font-size: var(--text-xs-font-size, 13px);
      line-height: var(--text-xs-line-height, 16px);
      letter-spacing: var(--text-xs-letter-spacing, 0px);
      font-weight: var(--font-weight-semibold, 600);
      color: hsl(var(--brand-shade-700, 235 67% 29%));
      white-space: nowrap;
      text-transform: uppercase;
      cursor: pointer;
      text-decoration: none;
      transition: background-color 0.15s ease, color 0.15s ease;
    }

    .block-theme-tags__badge:hover {
      background: hsl(var(--button-secondary-bg, 227 72% 51%));
      color: hsl(var(--button-cta-bg, 206 100% 92%));
    }

    .block-theme-tags__badge:focus-visible {
      outline: 2px solid hsl(var(--border-focus, 227 72% 51%));
      outline-offset: 2px;
    }

js:
const block = document.querySelector('.block-theme-tags');
    const badges = block.querySelectorAll('.block-theme-tags__badge');
    badges.forEach((badge, i) => {
      badge.style.opacity = '0';
      badge.style.transform = 'translateY(8px)';
      badge.style.transition = `opacity 0.3s cubic-bezier(0.16,1,0.3,1) ${i * 0.04}s, transform 0.3s cubic-bezier(0.16,1,0.3,1) ${i * 0.04}s`;
    });
    const io = new IntersectionObserver((entries) => {
      entries.forEach(e => {
        if (e.isIntersecting) {
          badges.forEach(b => { b.style.opacity = '1'; b.style.transform = 'translateY(0)'; });
          io.unobserve(e.target);
        }
      });
    }, { threshold: 0.15 });
    io.observe(block);
